import React, { useState, useEffect } from 'react';
import { APIProvider, Map, AdvancedMarker, Pin, InfoWindow } from '@vis.gl/react-google-maps';

// Fallback to Ho Chi Minh City if geolocation fails
const defaultLocation = { lat: 10.8231, lng: 106.6297 };

const StormShieldMap = ({ shelters = [], reports = [], alerts = [] }) => {
  const [center, setCenter] = useState(defaultLocation);
  const [myLocation, setMyLocation] = useState(null);

  const [selectedElement, setSelectedElement] = useState(null);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          const loc = {
            lat: position.coords.latitude,
            lng: position.coords.longitude
          };
          setMyLocation(loc);
          setCenter(loc);
        },
        (error) => {
          console.warn("Geolocation permission denied or failed. Fallback to HCMC.");
        }
      );
    }
  }, []);

  const handleMarkerClick = (element, type) => {
    setSelectedElement({ ...element, elementType: type });
  };

  return (
    <div style={{ height: '500px', width: '100%', borderRadius: '12px', overflow: 'hidden', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}>
      <APIProvider apiKey={process.env.REACT_APP_GOOGLE_MAPS_API_KEY}>
        <Map
          defaultZoom={13}
          center={center}
          onCenterChanged={(ev) => setCenter(ev.detail.center)}
          mapId="DEMO_MAP_ID"
        >
          {/* Current User Marker */}
          {myLocation && (
            <AdvancedMarker 
              position={myLocation} 
              onClick={() => handleMarkerClick({ lat: myLocation.lat, lng: myLocation.lng, title: 'You are here' }, 'USER')}
            >
              <Pin background={'#2563EB'} borderColor={'#FFFFFF'} glyphColor={'#FFFFFF'} />
            </AdvancedMarker>
          )}

          {/* Shelters */}
          {shelters.map(s => (
            <AdvancedMarker 
              key={`shelter-${s.id}`} 
              position={{ lat: s.latitude, lng: s.longitude }}
              onClick={() => handleMarkerClick(s, 'SHELTER')}
            >
              <Pin background={'#10B981'} borderColor={'#065F46'} glyphColor={'#FFFFFF'} />
            </AdvancedMarker>
          ))}

          {/* Reports */}
          {reports.map(r => (
            <AdvancedMarker 
              key={`report-${r.id}`} 
              position={{ lat: r.latitude, lng: r.longitude }}
              onClick={() => handleMarkerClick(r, 'REPORT')}
            >
              <Pin background={'#F59E0B'} borderColor={'#92400E'} glyphColor={'#FFFFFF'} />
            </AdvancedMarker>
          ))}

          {/* Alerts */}
          {alerts.map(a => (
            // Wait, alerts didn't have coordinates in our DTO!
            // Wait, Alert has 'affectedArea' string instead of lat/lng in MVP.
            // If they happen to have coordinates, we map them. 
            // In StormShield, Alerts didn't have lat/lng fields natively in entity. 
            // For safety and compatibility, if backend provides lat/lng on alert, map it.
            a.latitude && a.longitude ? (
              <AdvancedMarker 
                key={`alert-${a.id}`} 
                position={{ lat: a.latitude, lng: a.longitude }}
                onClick={() => handleMarkerClick(a, 'ALERT')}
              >
                 <Pin background={'#EF4444'} borderColor={'#991B1B'} glyphColor={'#FFFFFF'} />
              </AdvancedMarker>
            ) : null
          ))}

          {/* Info Window rendering */}
          {selectedElement && (
            <InfoWindow
              position={{ 
                lat: selectedElement.lat || selectedElement.latitude, 
                lng: selectedElement.lng || selectedElement.longitude 
              }}
              onCloseClick={() => setSelectedElement(null)}
            >
              <div style={{ padding: '4px', maxWidth: '200px' }}>
                {selectedElement.elementType === 'USER' && (
                  <strong style={{color: '#2563EB'}}>{selectedElement.title}</strong>
                )}

                {selectedElement.elementType === 'SHELTER' && (
                  <div>
                    <strong style={{color: '#10B981'}}>{selectedElement.name}</strong><br/>
                    Status: {selectedElement.status}<br/>
                    Capacity: {selectedElement.currentOccupancy}/{selectedElement.capacity}
                  </div>
                )}

                {selectedElement.elementType === 'REPORT' && (
                  <div>
                    <strong style={{color: '#F59E0B'}}>HAZARD: {selectedElement.reportType}</strong><br/>
                    Danger level: {selectedElement.dangerLevel}<br/>
                    Details: {selectedElement.description}
                  </div>
                )}

                {selectedElement.elementType === 'ALERT' && (
                  <div>
                    <strong style={{color: '#EF4444'}}>CRITICAL ALERT: {selectedElement.title}</strong><br/>
                    Severity: {selectedElement.severityLevel}<br/>
                    {selectedElement.description}
                  </div>
                )}
              </div>
            </InfoWindow>
          )}

        </Map>
      </APIProvider>
    </div>
  );
};

export default StormShieldMap;
